807→void Utility::sendLocalReply(const bool& is_reset, const EncodeFunctions& encode_functions,
   808→                             const LocalReplyData& local_reply_data) {
   809→  // encode_headers() may reset the stream, so the stream must not be reset before calling it.
   810→  ASSERT(!is_reset);
   811→  PreparedLocalReplyPtr prepared_local_reply =
   812→      prepareLocalReply(encode_functions, local_reply_data);
   813→
   814→  encodeLocalReply(is_reset, std::move(prepared_local_reply));
   815→}
